**A debounce function delays a function's execution until a specified time has passed without it being called again, preventing rapid successive calls.**  

```javascript
function debounce(func, delay) {
    let timeoutId;
    return function(...args) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => func.apply(this, args), delay);
    };
}

// Example usage: Log input value after user stops typing for 500ms
const searchInput = document.getElementById('search');
const logInput = () => console.log('Searching for:', searchInput.value);

searchInput.addEventListener('input', debounce(logInput, 500));
```
